  '[{"category": "Gruppe I", "q": "Hva står egentlig på spill når Norge møter Frankrike i gruppefinalen 26. juni?", "options": ["Den tapende av de to ryker ut av VM", "Gruppeseieren — begge lag er allerede klare for sluttspillet", "Frankrikes VM-plass i sluttspillet", "Norges VM-plass i sluttspillet"], "correct": 1, "explanation": "Både Norge og Frankrike har seks poeng og er allerede videre; kampen avgjør kun hvem som vinner gruppe I."}, {"category": "Norge", "q": "Norge er ubeseiret før gruppefinalen. Hvilke to seire tok de i de første kampene?", "options": ["4–1 over Irak og 3–2 over Senegal", "4–1 over Senegal og 3–2 over Irak", "3–1 over både Irak og Senegal", "2–0 over Irak og 1–0 over Senegal"], "correct": 0, "explanation": "Norge slo Irak 4–1 og Senegal 3–2 — full pott og seks poeng på to kamper."}, {"category": "Haaland", "q": "Hvor mange mål har Erling Haaland scoret i VM 2026 før gruppefinalen?", "options": ["Tre", "To", "Fire", "Seks"], "correct": 2, "explanation": "To mål mot Irak og to mot Senegal — fire mål på to kamper på sin VM-debut."}, {"category": "Frankrike", "q": "Hvor mange ganger har Frankrike vunnet VM?", "options": ["Tre ganger", "To ganger (1998 og 2018)", "Én gang (1998)", "Fire ganger"], "correct": 1, "explanation": "Frankrike vant hjemme i 1998 (3–0 over Brasil) og i Russland i 2018 (4–2 over Kroatia)."}, {"category": "Frankrike", "q": "Frankrikes trener Didier Deschamps har en sjelden dobbel-bragd i VM. Hvilken?", "options": ["Han var dommer i en VM-finale før trenerkarrieren", "Han har trent fire ulike landslag til VM-gull", "Han har vunnet VM både som kaptein (1998) og som trener (2018)", "Han har aldri tapt en VM-kamp som trener"], "correct": 2, "explanation": "Deschamps er én av bare tre som har vunnet VM som både spiller og trener (etter Zagallo og Beckenbauer). VM 2026 blir hans siste som Frankrike-sjef."}, {"category": "Mbappé", "q": "Kylian Mbappé satte en fransk rekord tidlig i VM 2026. Hvilken?", "options": ["Han ble Frankrikes mestkappede spiller", "Han ble den yngste VM-målscoreren noensinne", "Han ble første franskmann med VM-hat-trick", "Han ble Frankrikes mestscorende landslagsspiller gjennom tidene"], "correct": 3, "explanation": "Mbappés scoringer tok ham forbi alle andre på Frankrikes evige landslagsliste."}, {"category": "Stjernemøte", "q": "Gruppefinalen rammes ofte inn som et oppgjør mellom to av verdens fremste spisser. Hvilke to?", "options": ["Erling Haaland og Kylian Mbappé", "Erling Haaland og Lionel Messi", "Martin Ødegaard og Antoine Griezmann", "Alexander Sørloth og Olivier Giroud"], "correct": 0, "explanation": "Haalands fire VM-mål mot Mbappé, Frankrikes nye rekordscorer — et av mesterskapets heteste enkeltoppgjør."}, {"category": "Historie", "q": "Norge og Frankrike møttes aller første gang i 1923. Hvem vant den kampen?", "options": ["Kampen ble avlyst", "Frankrike, 3–0", "Norge, 2–0 i Paris", "Det endte uavgjort"], "correct": 2, "explanation": "Norge vant 2–0 i Paris i 1923; lagene har møttes et knippe ganger siden, sist i en privatlandskamp i 2014."}, {"category": "Frankrike", "q": "Frankrike har tapt to VM-finaler på straffespark. Mot hvilke to land?", "options": ["Brasil (1998) og Kroatia (2018)", "Spania og Tyskland", "Argentina (2006) og Italia (2022)", "Italia (2006) og Argentina (2022)"], "correct": 3, "explanation": "Frankrike tapte finalen mot Italia i 2006 og mot Argentina i 2022 — begge etter straffesparkkonkurranse."}, {"category": "VM 2026", "q": "Hvorfor er det historisk at Norge i det hele tatt spiller denne gruppefinalen?", "options": ["Det er Norges aller første VM noensinne", "Norge er regjerende verdensmester", "Det er første gang Norge vinner en VM-gruppe", "Det er Norges første VM siden 1998"], "correct": 3, "explanation": "Norge er tilbake i et herre-VM etter 28 år — sist var Frankrike 1998."}]'::jsonb, 'locked', 13, true
